obtener index [0] ƒ:
(texto) => {
    const regex = /^\[(\d+)\]\s*(.*)$/;
    const match = texto.match(regex);

    if (!match) {
        throw new Error('Formato inválido. Se esperaba: "[número] texto"');
    }

    return {
        indice: parseInt(match[1], 10),
        texto: match[2].trim(),
    };
}

