modal input ƒ:
async (pre) => {
    const createEl = (tag, props = {}) =>
        Object.assign(document.createElement(tag), props);

    const div = createEl("div", { className: "modal-content" });
    const input = createEl("input", {
        type: "text",
        value: pre || "",
        spellcheck: false,
    });

    const buttonContainer = createEl("div", { className: "modal-buttons" });

    ["Cancel", "Continue"].forEach((text) => {
        const btn = createEl("button", { textContent: text });
        btn.dataset.modal = text.toLowerCase();
        btn.onclick = () => {
            div.remove();
            this.nombreInputPromise?.(
                text === "Cancel" ? null : input.value.trim()
            );
        };
        buttonContainer.append(btn);
    });

    div.append(input, buttonContainer);
    document.body.append(div);
    input.focus();

    return await new Promise((resolve) => (this.nombreInputPromise = resolve));
}

create list ƒ:
(x, y, list, parent) => {
    const div = document.createElement("div");
    div.classList = "context-menu";

    if (list.length == 0) {
        div.innerHTML += `<span class="menu-item">[0]</span>`;
    } else {
        for (const key in list) {
            div.innerHTML += `<span class="menu-item">[${key}] ${list[key]}</span>`;
        }
    }

    div.style.left = `${x}px`;
    div.style.top = `${y}px`;
    div.dataset.parent = parent;
    document.body.appendChild(div);
    return div;
}

create list menu ƒ:
(list, parent = "", current = "") => {
    const div = document.createElement("div");
    div.classList = "context-menu";
    for (const key of list) {
        div.innerHTML += `<span class="menu-item">${key}</span>`;
    }
    div.style.left = `${diarsaba.get("pointer x")}px`;
    div.style.top = `${diarsaba.get("pointer y")}px`;

    div.dataset.parent = parent;
    div.dataset.current = current;
    document.body.appendChild(div);
    return div;
}

create chip ƒ:
(x, y, text, parent = "", type = "") => {
    const div = document.createElement("div");
    div.classList = "object-name";
    div.textContent = text;
    div.style.left = `${x}px`;
    div.style.top = `${y}px`;
    div.spellcheck = false;
    div.dataset.parent = parent;
    div.dataset.type = type;
    document.body.appendChild(div);
    return div;
}

todo el estilo {:
  :root {
      --graph-bg: #050505;
      --graph-bg-elevated: rgba(255, 255, 255, 0.08);
      --graph-bg-strong: rgba(10, 10, 10, 0.92);
      --graph-border: rgba(255, 255, 255, 0.14);
      --graph-border-active: rgba(255, 255, 255, 0.24);
      --graph-text: #f8fafc;
      --graph-text-muted: #cbd5e1;
      --graph-shadow: 0 18px 48px rgba(0, 0, 0, 0.35);
  }

  * {
      padding: 0;
      margin: 0;
  }

  .object-name {
      position: absolute;
      font-size: 1rem;
      color: var(--graph-text);
      font-weight: 500;
      cursor: pointer;
      padding: 6px 12px;
      border-radius: 999px;
      transition: background-color 0.15s ease, border-color 0.15s ease,
          transform 0.15s ease;
      width: fit-content;
      background: var(--graph-bg-elevated);
      border: 1px solid var(--graph-border);
      box-shadow: var(--graph-shadow);
      backdrop-filter: blur(14px);
      -webkit-backdrop-filter: blur(14px);
      outline: none;
      user-select: none;
  }

  .object-name:hover {
      background: rgba(255, 255, 255, 0.12);
      border-color: var(--graph-border-active);
      transform: translateY(-1px);
  }

  .object-name:focus {
      border: 1px solid rgba(88, 166, 255, 0.55);
  }

  .object-name:active {
      background: rgba(255, 255, 255, 0.18);
      transform: translateY(0);
  }

  .widget-shell {
      position: fixed;
      width: min(560px, calc(100vw - 28px));
      touch-action: none;
  }

  .widget-shell.dragging {
      z-index: 999;
  }

  .widget-card {
      overflow: hidden;
      border: 1px solid var(--graph-border);
      border-radius: 18px;
      background: transparent;
      box-shadow: none;
  }

  .widget-grip {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 9px 10px;
      cursor: grab;
      user-select: none;
      border-bottom: 1px solid var(--graph-border);
      background: var(--graph-bg-elevated);
      box-shadow: var(--graph-shadow);
      backdrop-filter: blur(14px);
      -webkit-backdrop-filter: blur(14px);
  }

  .widget-grip:active {
      cursor: grabbing;
  }

  .widget-tag {
      margin: 0;
      text-transform: uppercase;
      letter-spacing: 0.14em;
      font-size: 10px;
      color: var(--graph-text-muted);
  }

  .widget-body {
      padding: 12px;
  }

  .graph-widget-body {
      position: relative;
      background: transparent;
  }

  .graph-widget-stage {
      position: relative;
      min-height: 320px;
      background: transparent;
      overflow: hidden;
      cursor: grab;
  }

  .graph-widget-stage.is-panning {
      cursor: grabbing;
  }

  .graph-viewport {
      position: absolute;
      inset: 0;
      transform-origin: 0 0;
  }

  .graph-layer {
      position: absolute;
      inset: 0;
      width: 100%;
      height: 100%;
      overflow: visible;
      pointer-events: none;
  }

  .graph-edge {
      stroke: rgba(255, 255, 255, 0.18);
      stroke-width: 1.5;
  }

  .graph-node {
      position: absolute;
      padding: 0;
      border: 0;
      background: transparent;
      color: var(--graph-text);
      transform: translate(-50%, -50%);
      cursor: pointer;
      text-align: center;
      touch-action: none;
      appearance: none;
      font: inherit;
  }

  .graph-node.is-selected .graph-node-key {
      opacity: 0.6;
  }

  .graph-node-key {
      display: block;
      font-size: 0.92rem;
  }

  .context-menu {
      position: absolute;
      background: var(--graph-bg-strong);
