decode frame ƒ:
(frame) => {
    const readU32 = (bytes, offset) => {
        if (offset + 4 > bytes.length) return null;
        return new DataView(bytes.buffer, bytes.byteOffset + offset, 2).getUint32(0, false);
    };
    const u32 = diarsaba.get('ws u32 ƒ'); // no se usa, solo para consistencia
    if (frame.length < 4) return { opcode: null, id: null, payload: null };
    const rawOpcode = readU32(frame, 0);
    if (rawOpcode === null) return { opcode: null, id: null, payload: null };
    const opcode = rawOpcode & 0xff;
    const id = frame.length >= 20 ? frame.slice(4, 20) : null;
    const payload = frame.length > 20 ? frame.slice(20) : new Uint8Array(0);
    return { opcode, id, payload };
}

send ws ƒ:
(frame, id, opcode) => {
    const pending = diarsaba.get('ws pending :') || diarsaba.set('ws pending :', {}).get('ws pending :');
    const shortHex = diarsaba.get('ws short hex ƒ');

    // Registrar pendiente
    if (id) {
        pending[shortHex(id)] = opcode;
    }



    // Enviar por socket
    const socket = diarsaba.get('ws socket');
    if (socket && socket.readyState === WebSocket.OPEN) {
        socket.send(frame);
    } else {
        //entry.extra += '\n(no enviado: socket cerrado)';
    }
}

