    if (name == "" || name == null)
        return


    const place_exist = diarsaba.get(name)
    //si no existe creamos su place
    if (place_exist == null || place_exist == undefined) {
        diarsaba.set(name, {})
    } else {
        //si ya existe no hacemos nada
    }


    //tenemos ahora el chip con el que interactuar
    const chip = diarsaba.get("create chip ƒ")(
        diarsaba.get("open x $"),
        diarsaba.get("open y $"),
        name,
        "",
        "@");


    const current_place_name = diarsaba.get("current place §")

    if (current_place_name == null || current_place_name == undefined) {
        //si no existe un place ahora somos el place
        diarsaba.set("current place §", name)
    } else {
        // 1. Declaramos la variable y evitamos que sea undefined
        let current_place = diarsaba.get(current_place_name) || {};

        // 2. Usamos un nombre de variable más seguro (asumiendo que 'name' viene de otro lado)
        const itemKey = name;

        // 3. Creamos un nuevo objeto (inmutabilidad) usando el spread operator (...)
        const updated_place = {
            ...current_place,
            [itemKey]: {
                x: diarsaba.get("open x $"),
                y: diarsaba.get("open y $")
            }
        };

        // 4. Guardamos el nuevo objeto
        diarsaba.set(current_place_name, updated_place);
    }

}

